//! D.PEEL.VALUE.1 — Outer peel on the value manifold.
//!
//! Operates on k unique color values (k ~ 5-10 for ARC).
//! Searches for the category-level transformation: which color maps to which.
//! Scoring: cocycle residual of (T_candidate - T_target) in Z. O(k³).
//! Fed by hearing sense (value spectrum).
//!
//! The outermost shell of the nested peel architecture.
//! Its output (T_value) constrains the middle peel (object manifold).

use super::super::vocabulary::*;

/// Result of the value-level peel.
#[derive(Debug, Clone)]
pub struct ValuePeelResult {
    /// The category map: for each source value, the target value.
    /// Index corresponds to unique_vals ordering.
    pub category_map: Vec<(i64, i64)>,
    /// Cocycle residual of the value transformation in Z.
    /// Zero = perfect relational cohesion at the value level.
    pub cocycle_residual: i64,
    /// Torsion order of the value transformation.
    /// The smallest p such that applying the map p times returns to identity.
    /// Measured by following permutation cycles. lcm of all cycle lengths.
    pub torsion_order: u16,
    /// Which thought achieved this result.
    pub best_thought: Thought,
    /// How many thoughts were evaluated.
    pub thoughts_evaluated: u32,
}

/// Measure the torsion order of a value map.
/// Follows permutation cycles: for each source value, trace
/// src → map(src) → map(map(src)) → ... until return to src.
/// The torsion order is the lcm of all cycle lengths.
fn measure_value_torsion(category_map: &[(i64, i64)]) -> u16 {
    let mut visited = vec![false; category_map.len()];
    let mut lcm_order: u64 = 1;

    for start in 0..category_map.len() {
        if visited[start] { continue; }

        // Follow the cycle from this starting value
        let mut cycle_len: u64 = 0;
        let mut current = start;
        loop {
            if current >= category_map.len() || visited[current] { break; }
            visited[current] = true;
            cycle_len += 1;

            // Find where this value maps to
            let target_val = category_map[current].1;
            let next = category_map.iter().position(|(s, _)| *s == target_val);
            match next {
                Some(idx) if !visited[idx] => current = idx,
                _ => break,
            }
        }

        // lcm of cycle lengths
        (cycle_len > 0).then(|| {
            let gcd = {
                let (mut a, mut b) = (lcm_order, cycle_len);
                while b != 0 { let t = b; b = a % b; a = t; }
                a
            };
            lcm_order = lcm_order / gcd * cycle_len;
        });
    }

    lcm_order.min(256) as u16
}

/// Peel the value manifold: find the category-level transformation.
///
/// For each unique input value, determine what it maps to in the output.
/// Then search the value vocabulary (ColorPermute, UniformShift) for
/// the thought that best reproduces this mapping.
///
/// Scoring is the cocycle residual of the difference between candidate
/// and target category Deltas — measured across all triples (i,j,k)
/// of unique values. This is for_each_residual in Z. O(k³).
///
/// The value peel does not know about positions, objects, or cells.
/// It sees only the value manifold — the relationships between colors.
pub fn peel_value_manifold(
    train_pairs: &[(Vec<i64>, Vec<i64>)],
    rows: usize,
    cols: usize,
    genomic_value_ops: &[crate::engine::ComposedOperator],
) -> ValuePeelResult {
    let n = train_pairs[0].0.len().min(train_pairs[0].1.len());

    // Collect unique input values — the entities of the value manifold
    let mut unique_vals: Vec<i64> = Vec::new();
    for &v in &train_pairs[0].0 {
        if !unique_vals.contains(&v) { unique_vals.push(v); }
    }
    unique_vals.sort();
    let k = unique_vals.len();

    // Build target category map: input_val → dominant output_val (consensus across pairs)
    let mut target_cats: Vec<i64> = Vec::with_capacity(k);
    for &sv in &unique_vals {
        let mut counts: Vec<(i64, usize)> = Vec::new();
        for (inp, out) in train_pairs {
            for idx in 0..inp.len().min(out.len()) {
                if inp[idx] == sv {
                    let tv = out[idx];
                    let entry = counts.iter_mut().find(|(v, _)| *v == tv);
                    match entry {
                        Some(e) => e.1 += 1,
                        None => counts.push((tv, 1)),
                    }
                }
            }
        }
        target_cats.push(
            counts.iter().max_by_key(|(_, c)| *c).map(|(v, _)| *v).unwrap_or(sv)
        );
    }

    // Target T in Z: T_target[i][j] = target_cats[j] - target_cats[i]
    let target_t: Vec<Vec<i64>> = (0..k).map(|i|
        (0..k).map(|j| target_cats[j] - target_cats[i]).collect()
    ).collect();

    // Cocycle residual measurement in Z
    let measure_cocycle = |cand_cats: &[i64]| -> i64 {
        let mut residual = 0i64;
        for i in 0..k {
            for j in 0..k {
                if j == i { continue; }
                for ki in 0..k {
                    if ki == i || ki == j { continue; }
                    let d_ik = (cand_cats[ki] - cand_cats[i]) - target_t[i][ki];
                    let d_ij = (cand_cats[j] - cand_cats[i]) - target_t[i][j];
                    let d_jk = (cand_cats[ki] - cand_cats[j]) - target_t[j][ki];
                    residual += (d_ik - d_ij - d_jk).abs();
                }
            }
        }
        residual
    };

    // Build vocabulary: value-level thoughts + genomic value operators
    let mut vocab = value_vocabulary();
    for op in genomic_value_ops {
        vocab.push(Thought::Genomic {
            opcode: op.opcode,
            parameter: op.parameter,
            sigma: op.sigma.clone(),
        });
    }

    // Evaluate each thought: apply to input, extract candidate categories, measure cocycle
    let initial_map: Vec<(i64, i64)> = unique_vals.iter().zip(target_cats.iter()).map(|(&s, &t)| (s, t)).collect();
    let mut best = ValuePeelResult {
        torsion_order: measure_value_torsion(&initial_map),
        category_map: initial_map,
        cocycle_residual: i64::MAX,
        best_thought: Thought::Identity,
        thoughts_evaluated: 0,
    };

    for thought in &vocab {
        // Apply thought to first training input
        let predicted = thought.apply_to_values(&train_pairs[0].0, rows, cols);

        // Extract candidate categories
        let mut cand_cats: Vec<i64> = Vec::with_capacity(k);
        for &sv in &unique_vals {
            let mut counts: Vec<(i64, usize)> = Vec::new();
            for idx in 0..n {
                if train_pairs[0].0[idx] == sv && idx < predicted.len() {
                    let dv = predicted[idx];
                    let entry = counts.iter_mut().find(|(v, _)| *v == dv);
                    match entry {
                        Some(e) => e.1 += 1,
                        None => counts.push((dv, 1)),
                    }
                }
            }
            cand_cats.push(
                counts.iter().max_by_key(|(_, c)| *c).map(|(v, _)| *v).unwrap_or(sv)
            );
        }

        let residual = measure_cocycle(&cand_cats);
        best.thoughts_evaluated += 1;

        // C(T) selects — lowest cocycle residual wins
        (residual < best.cocycle_residual).then(|| {
            best.cocycle_residual = residual;
            best.best_thought = thought.clone();
            let new_map: Vec<(i64, i64)> = unique_vals.iter().zip(cand_cats.iter()).map(|(&s, &c)| (s, c)).collect();
            best.torsion_order = measure_value_torsion(&new_map);
            best.category_map = new_map;
        });
    }

    best
}
